sinks.expression:
printf(
						/* translators: 1: Astra theme from wordpress.org*/
						esc_html__( 'Custom Fonts Plugin requires minimum 1.0.16 version of the Astra Theme.', 'custom-fonts' ),
						esc_url( 'https://downloads.wordpress.org/theme/astra.zip' )
					)

array_filter(
							$font_families,
							function( $value ) {
								if ( ! empty( $value['isBcf'] ) ) {
									return false;
								}
								return true;
							}
						)

array_filter(
						$bcf_global_fse_fonts,
						function( $value ) use ( $font ) {
							if ( $font['fontFamily'] === $value['value'] ) {
								return false;
							}
							return true;
						}
					)

